parameters.jsCode:
// Get the incoming webhook data
const webhookData = $input.first().json;
const requestBody = webhookData.body || webhookData;

// Get agent data from Supabase
const agentData = $('Get Agent Settings').first().json;

const callId = requestBody.call_id;
const agentId = requestBody.agent_id;
const fromNumber = requestBody.from_number;

console.log('=== AVAILABILITY CHECK START ===');
console.log('Call ID:', callId);
console.log('Agent ID:', agentId);
console.log('Agent Data:', JSON.stringify(agentData));

// Parse availability settings from the database
let availabilitySettings;
try {
  if (typeof agentData.availability_settings === 'string') {
    availabilitySettings = JSON.parse(agentData.availability_settings);
  } else {
    availabilitySettings = agentData.availability_settings;
  }
} catch (e) {
  console.log('ERROR parsing availability settings:', e);
  availabilitySettings = { enabled: false };
}

console.log('Parsed Availability Settings:', JSON.stringify(availabilitySettings));

// If availability check is disabled or settings don't exist, always return available
if (!availabilitySettings || !availabilitySettings.enabled) {
  console.log('✅ Availability check DISABLED - returning available');
  return {
    json: {
      call_id: callId,
      agent_id: agentId,
      from_number: fromNumber,
      is_available: true,
      reason: 'availability_check_disabled',
      current_time: new Date().toISOString(),
      timezone: 'N/A'
    }
  };
}

// Get timezone and unavailable hours from settings
const timezone = availabilitySettings.timezone || 'America/New_York';
const unavailableStartTime = availabilitySettings.unavailable_start_time || '20:00';
const unavailableEndTime = availabilitySettings.unavailable_end_time || '08:00';

console.log(`⏰ Checking availability for agent ${agentId}...`);
console.log(`  Timezone: ${timezone}`);
console.log(`  Unavailable: ${unavailableStartTime} - ${unavailableEndTime}`);

// Get current time in the agent's timezone
const now = new Date();
const formatter = new Intl.DateTimeFormat('en-US', {
  timeZone: timezone,
  hour: '2-digit',
  minute: '2-digit',
  hour12: false
});

const parts = formatter.formatToParts(now);
const hour = parseInt(parts.find(p => p.type === 'hour').value);
const minute = parseInt(parts.find(p => p.type === 'minute').value);
const currentMinutes = hour * 60 + minute;

// Parse unavailable times
const [startHour, startMinute] = unavailableStartTime.split(':').map(Number);
const [endHour, endMinute] = unavailableEndTime.split(':').map(Number);
const startMinutes = startHour * 60 + startMinute;
const endMinutes = endHour * 60 + endMinute;

console.log(`  Current time: ${hour}:${minute} (${currentMinutes} minutes)`);
console.log(`  Start unavailable: ${startHour}:${startMinute} (${startMinutes} minutes)`);
console.log(`  End unavailable: ${endHour}:${endMinute} (${endMinutes} minutes)`);

// Check if current time is in unavailable range
let isAvailable = true;

if (startMinutes > endMinutes) {
  // Overnight range (e.g., 20:00 to 08:00)
  // UNAVAILABLE if: currentTime >= startTime OR currentTime < endTime
  // AVAILABLE if: currentTime < startTime AND currentTime >= endTime
  isAvailable = currentMinutes < startMinutes && currentMinutes >= endMinutes;
  console.log(`  Range type: OVERNIGHT (crosses midnight)`);
} else {
  // Same day range (e.g., 12:00 to 18:00)
  // UNAVAILABLE if: currentTime >= startTime AND currentTime < endTime
  // AVAILABLE if: currentTime < startTime OR currentTime >= endTime
  isAvailable = currentMinutes < startMinutes || currentMinutes >= endMinutes;
  console.log(`  Range type: SAME DAY`);
}

console.log(`  Result: ${isAvailable ? '✅ AVAILABLE' : '❌ UNAVAILABLE'}`);
console.log('=== AVAILABILITY CHECK END ===');

// Return the result
return {
  json: {
    call_id: callId,
    agent_id: agentId,
    from_number: fromNumber,
    is_available: isAvailable,
    current_time: `${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`,
    timezone: timezone,
    unavailable_start: unavailableStartTime,
    unavailable_end: unavailableEndTime,
    reason: isAvailable ? 'within_business_hours' : 'outside_business_hours'
  }
};

