parameters.jsCode:
const items = $input.all();

return items.map(item => {
  const call = item.json.body?.call || item.json.call || item.json;

  const formatTimestamp = (ts) => ts ? new Date(ts).toISOString().replace('T', ' ').substring(0, 19) : null;

  return {
    json: {
      ...item.json,
      start_time_formatted: formatTimestamp(call.start_timestamp),
      end_time_formatted: formatTimestamp(call.end_timestamp),
      duration_formatted: call.duration_ms ? `${Math.floor(call.duration_ms / 60000)}m ${Math.floor((call.duration_ms % 60000) / 1000)}s` : '0s'
    }
  };
});

